class Solution:
    def maxStarSum(self, vals, edges, k):
        n = len(vals)
        neighbors = [[] for _ in range(n)]
        for a, b in edges:
            neighbors[a].append(vals[b])
            neighbors[b].append(vals[a])
        best = None
        for i in range(n):
            ns = sorted(neighbors[i], reverse=True)
            total = vals[i]
            count = 0
            for v in ns:
                if count >= k or v <= 0:
                    break
                total += v
                count += 1
            if best is None or total > best:
                best = total
        return best

