class Solution:
    def maxStarSum(self, vals, edges, k):
        n = len(vals)
        adj = [[] for _ in range(n)]
        for a, b in edges:
            if vals[b] > 0:
                adj[a].append(vals[b])
            if vals[a] > 0:
                adj[b].append(vals[a])
        best = float('-inf')
        for i in range(n):
            top = sorted(adj[i], reverse=True)[:k]
            best = max(best, vals[i] + sum(top))
        return best

