var maxStarSum = function(vals, edges, k) {
    const n = vals.length;
    const adj = Array.from({ length: n }, () => []);
    for (const [a, b] of edges) {
        if (vals[b] > 0) adj[a].push(vals[b]);
        if (vals[a] > 0) adj[b].push(vals[a]);
    }
    let best = -Infinity;
    for (let i = 0; i < n; i++) {
        const top = adj[i].slice().sort((x, y) => y - x).slice(0, k);
        const sum = top.reduce((s, v) => s + v, 0);
        if (vals[i] + sum > best) best = vals[i] + sum;
    }
    return best;
};
